import { Map } from "../core/map";
import { IControl } from "./control";

import { ControlPosition as maplibreControlPosition } from "maplibre-gl";

/**
 * Options for configuring the {@link LogoControl}.
 */
export type LogoControlOptions = {};

/**
 * Default options for the {@link LogoControl}.
 */
export const defaultLogoControlOptions: LogoControlOptions = {};

/**
 * Displays the Maptoolkit watermark.
 */
export class LogoControl implements IControl {
  options: LogoControlOptions;
  _map?: Map;
  _container?: HTMLElement;

  /**
   * Creates an instance of LogoControl.
   * @param options - Options for configuring the compass control.
   */
  constructor(options?: LogoControlOptions) {
    this.options = Object.assign(defaultLogoControlOptions, options);
  }

  getDefaultPosition(): maplibreControlPosition {
    return "bottom-left";
  }

  onAdd(map: Map) {
    this._map = map;
    this._container = document.createElement("div");
    this._container.classList.add("maplibregl-ctrl", "maptoolkit-ctrl", "maptoolkit-ctrl-logo");
    const anchor = document.createElement("a");
    anchor.classList.add("maptoolkit-ctrl-logo-anchor");
    anchor.href = "https://www.maptoolkit.com";
    anchor.target = "_blank";
    const image = document.createElement("img");
    image.classList.add("maptoolkit-ctrl-logo-image");
    image.src =
      "data:image/png;base64,";
    image.alt = "Maptoolkit Logo";
    anchor.appendChild(image);
    this._container.appendChild(anchor);
    return this._container;
  }

  onRemove() {
    if (this._container?.parentNode) {
      this._container.parentNode.removeChild(this._container);
    }
    this._map = undefined;
  }
}
